import React, { useEffect, useMemo, useState } from 'react'
import { Download, ExternalLink, Loader } from 'react-feather'
import cn from 'classnames'
import JSZip from 'jszip'
import { saveAs } from 'file-saver'
import { getBlobData } from 'api'
import { getImageUrl } from 'utils/helper'
import {
  SLICE_PLATFORMS,
  OUTPUT_FORMATS,
  getRasterExportSettings,
  getScale,
  getCleanName,
  loadImage,
  canvasToBlob,
  getOutputName,
  getBaseSize
} from 'utils/sliceExport'
import './export-item.scss'

const legacySave = ({ e, name, imageUrl, isHttpServer, setDownloading }) => {
  if (isHttpServer) {
    e.preventDefault()
    setDownloading(true)
    getBlobData(imageUrl)
      .then(blob => {
        saveAs(blob, name)
        setDownloading(false)
      })
  }
}

const ExportItem = ({ exportSetting, exportSettings, mode, isMock }) => {
  const [ isDownloading, setDownloading ] = useState(false)
  const [ format, setFormat ] = useState('PNG')
  const [ platform, setPlatform ] = useState('ios')
  const [ selectedKeys, setSelectedKeys ] = useState(['1x', '2x', '3x'])
  const [ previewSize, setPreviewSize ] = useState(null)
  const { protocol } = window.location
  const isHttpServer = /^http/.test(protocol)
  const groupedExportSettings = useMemo(
    () => getRasterExportSettings(exportSettings || (exportSetting ? [exportSetting] : [])),
    [exportSetting, exportSettings]
  )
  const sourceSetting = useMemo(
    () =>
      groupedExportSettings
        .slice()
        .sort((a, b) => getScale(b) - getScale(a))[0],
    [groupedExportSettings]
  )

  useEffect(() => {
    if (!sourceSetting) return
    const imageUrl = sourceSetting.offlineDataUrl || getImageUrl(sourceSetting, mode, isMock)
    loadImage(imageUrl).then(image => {
      const scale = getScale(sourceSetting)
      setPreviewSize(getBaseSize(image, scale))
    })
  }, [sourceSetting, mode, isMock])

  if (!exportSettings) {
    const name = exportSetting.fileName
    const imageUrl = getImageUrl(exportSetting, mode, isMock)
    return <a
        href={imageUrl}
        target="_blank"
        rel="noopener noreferrer"
        className={cn('export-item', {'export-item-downloading': isDownloading})}
        onClick={e => legacySave({ e, name, imageUrl, isHttpServer, setDownloading })}
      >
        <div style={{backgroundImage: `url(${imageUrl})`}}/>
        <span>{ name }</span>
        {
          isDownloading ?
          <Loader size={14} className="motion-loading"/> :
          (isHttpServer ? <Download size={14}/> : <ExternalLink size={14}/>)
        }
      </a>
  }

  if (!sourceSetting) {
    return null
  }

  const imageUrl = sourceSetting.offlineDataUrl || getImageUrl(sourceSetting, mode, isMock)
  const baseName = getCleanName(sourceSetting)
  const densityItems = SLICE_PLATFORMS[platform]

  const handlePlatformChange = e => {
    const nextPlatform = e.target.value
    setPlatform(nextPlatform)
    setSelectedKeys(SLICE_PLATFORMS[nextPlatform].map(({ key }) => key))
  }

  const handleDensityChange = key => {
    setSelectedKeys(keys =>
      keys.indexOf(key) > -1 ? keys.filter(item => item !== key) : [...keys, key]
    )
  }

  const handleDownload = async () => {
    if (!selectedKeys.length || isDownloading) return

    setDownloading(true)
    const sourceImage = await loadImage(imageUrl)
    const sourceScale = getScale(sourceSetting)
    const baseWidth = sourceImage.naturalWidth / sourceScale
    const baseHeight = sourceImage.naturalHeight / sourceScale
    const zip = new JSZip()

    await Promise.all(
      densityItems
        .filter(({ key }) => selectedKeys.indexOf(key) > -1)
        .map(async density => {
          const width = Math.max(1, Math.round(baseWidth * density.scale))
          const height = Math.max(1, Math.round(baseHeight * density.scale))
          const blob = await canvasToBlob(sourceImage, width, height, format)
          zip.file(getOutputName(baseName, density, format, platform), blob)
        })
    )

    const zipContent = await zip.generateAsync({ type: 'blob' })
    saveAs(zipContent, `${baseName}-${platform}.zip`)
    setDownloading(false)
  }

  return (
    <div className="export-downloader">
      <label className="export-downloader-label">切图名称</label>
      <input className="export-downloader-input" value={baseName} readOnly/>

      <div className="export-downloader-preview">
        <img src={imageUrl} alt={baseName}/>
      </div>

      <div className="export-downloader-grid">
        <label>
          <span>下载切图样式</span>
          <select value={format} onChange={e => setFormat(e.target.value)}>
            {OUTPUT_FORMATS.map(item => <option key={item} value={item}>{item}</option>)}
          </select>
        </label>
        <label>
          <span>切图使用平台</span>
          <select value={platform} onChange={handlePlatformChange}>
            <option value="ios">iOS</option>
            <option value="android">Android</option>
          </select>
        </label>
      </div>

      <ul className="export-density-list">
        {densityItems.map(density => {
          const checked = selectedKeys.indexOf(density.key) > -1
          const width = previewSize ? Math.round(previewSize.width * density.scale) : 0
          const height = previewSize ? Math.round(previewSize.height * density.scale) : 0
          return (
            <li key={density.key}>
              <label>
                <input
                  type="checkbox"
                  checked={checked}
                  onChange={() => handleDensityChange(density.key)}
                />
                <span>{density.label}</span>
              </label>
              <em>{previewSize ? `${width}px x ${height}px` : ''}</em>
            </li>
          )
        })}
      </ul>

      <button className="export-downloader-button" disabled={!selectedKeys.length || isDownloading} onClick={handleDownload}>
        {isDownloading ? '正在生成...' : '下载切图'}
      </button>
    </div>
  )
}

export default ExportItem
