import React from 'react'
import cn from 'classnames'
import './artboard-view-controls.scss'

export const ARTBOARD_VIEW_MODES = [
  { key: 'list', label: '列表', defaultSize: 48 },
  { key: 'multi', label: '多级', defaultSize: 200 },
  { key: 'waterfall', label: '瀑布', defaultSize: 400 },
  { key: 'fill', label: '填充', defaultSize: 160 },
  { key: 'icon', label: '图标', defaultSize: 128 },
  { key: 'artboard', label: '画板', defaultSize: 200 }
]

const ArtboardViewControls = function ({
  settings,
  onChange,
  onReset,
  onSave
}) {
  const currentView = ARTBOARD_VIEW_MODES.find(({ key }) => key === settings.viewMode) || ARTBOARD_VIEW_MODES[0]
  const thumbnailSize = settings.thumbnailSizes[settings.viewMode] || currentView.defaultSize

  function updateThumbnailSize (size) {
    onChange({
      thumbnailSizes: {
        ...settings.thumbnailSizes,
        [settings.viewMode]: Math.max(32, Math.min(420, Number(size)))
      }
    })
  }

  return (
    <div className="artboard-view-controls">
      <div className="artboard-view-toolbar">
        {ARTBOARD_VIEW_MODES.map(view => (
          <button
            key={view.key}
            className={cn('artboard-view-button', `artboard-view-${view.key}`, { selected: settings.viewMode === view.key })}
            title={view.label}
            onClick={() => onChange({ viewMode: view.key })}
          >
            <span className="view-icon"/>
            <em>{view.label}</em>
          </button>
        ))}
      </div>
      <div className="artboard-view-settings">
        <div className="settings-row settings-size-row">
          <span>大小</span>
          <button onClick={() => updateThumbnailSize(thumbnailSize - 16)}>−</button>
          <input type="range" min="32" max="420" step="8" value={thumbnailSize} onChange={e => updateThumbnailSize(e.target.value)}/>
          <button onClick={() => updateThumbnailSize(thumbnailSize + 16)}>+</button>
          <strong>{thumbnailSize}</strong>
        </div>
        <div className="settings-row">
          <span>隐藏文件名</span>
          <label className="switch"><input type="checkbox" checked={settings.hideFileName} onChange={e => onChange({ hideFileName: e.target.checked })}/><i/></label>
        </div>
        <div className="settings-row">
          <span>隐藏资源数</span>
          <label className="switch"><input type="checkbox" checked={settings.hideResourceCount} onChange={e => onChange({ hideResourceCount: e.target.checked })}/><i/></label>
        </div>
        <div className="settings-row">
          <span>显示属性</span>
          <select value={settings.displayAttribute} onChange={e => onChange({ displayAttribute: e.target.value })}>
            <option value="none">无</option>
            <option value="size">尺寸</option>
            <option value="type">类型</option>
          </select>
        </div>
        <div className="settings-row">
          <span>自动播放</span>
          <select value={settings.autoplay} onChange={e => onChange({ autoplay: e.target.value })}>
            <option value="animated">动画图片</option>
            <option value="none">不自动播放</option>
          </select>
        </div>
        <div className="settings-row">
          <span>间距</span>
          <select value={settings.spacing} onChange={e => onChange({ spacing: e.target.value })}>
            <option value="auto">自动</option>
            <option value="compact">紧凑</option>
            <option value="normal">标准</option>
            <option value="loose">宽松</option>
          </select>
        </div>
        <div className="settings-row settings-sort-row">
          <span>排序</span>
          <button className={cn({ selected: settings.sortDirection === 'desc' })} onClick={() => onChange({ sortDirection: 'desc' })}>↓</button>
          <button className={cn({ selected: settings.sortDirection === 'asc' })} onClick={() => onChange({ sortDirection: 'asc' })}>↑</button>
          <select value={settings.sortField} onChange={e => onChange({ sortField: e.target.value })}>
            <option value="updated">更新时间</option>
            <option value="name">名称</option>
            <option value="size">尺寸</option>
          </select>
        </div>
      </div>
      <div className="settings-saved-row">
        <label>
          <input type="checkbox" checked={settings.savedViewEnabled} onChange={e => onChange({ savedViewEnabled: e.target.checked })}/>
          <span>保存的视图：{currentView.label}</span>
        </label>
        <button>...</button>
      </div>
      <div className="settings-actions">
        <button onClick={onReset}>回到默认</button>
        <button onClick={onSave}>重新保存视图</button>
      </div>
    </div>
  )
}

export default ArtboardViewControls
